public class TagDataServlet extends HttpServlet { private static final int MAX = WebloggerConfig . getIntProperty ( "services.tagdata.max" , 30 ) ; protected void doPost ( HttpServletRequest request , HttpServletResponse response ) throws ServletException , IOException { doGet ( request , response ) ; } public void doGet ( HttpServletRequest request , HttpServletResponse response ) throws ServletException , IOException { String [ ] pathInfo = new String [ 0 ] ; boolean siteWide ; String handle ; String prefix ; String format = "json" ; int page = 0 ; if ( request . getPathInfo ( ) != null ) { pathInfo = Utilities . stringToStringArray ( request . getPathInfo ( ) , "/" ) ; } if ( pathInfo . length == 0 ) { siteWide = true ; handle = WebloggerRuntimeConfig . getProperty ( "site.frontpage.weblog.handle" ) ; } else if ( pathInfo . length == 2 && "weblog" . equals ( pathInfo [ 0 ] ) ) { siteWide = false ; handle = pathInfo [ 1 ] ; } else { response . sendError ( HttpServletResponse . SC_BAD_REQUEST , "Malformed URL" ) ; return ; } prefix = request . getParameter ( "prefix" ) ; if ( request . getParameter ( "format" ) != null ) { format = request . getParameter ( "format" ) ; } try { page = Integer . parseInt ( request . getParameter ( "page" ) ) ; } catch ( Exception ignored ) { } Weblogger roller = WebloggerFactory . getWeblogger ( ) ; List < TagStat > tags ; Weblog weblog ; try { WeblogManager wmgr = roller . getWeblogManager ( ) ; WeblogEntryManager emgr = roller . getWeblogEntryManager ( ) ; weblog = wmgr . getWeblogByHandle ( handle ) ; tags = emgr . getTags ( siteWide ? null : weblog , null , prefix , page * MAX , MAX + 1 ) ; } catch ( WebloggerException we ) { response . sendError ( HttpServletResponse . SC_INTERNAL_SERVER_ERROR , "ERROR fetching tags" ) ; return ; } if ( "json" . equals ( format ) ) { response . setContentType ( "application/json; charset=utf-8" ) ; PrintWriter pw = response . getWriter ( ) ; pw . println ( "{ \"prefix\": \"" + ( prefix == null ? "" : prefix ) + "\"," ) ; pw . println ( "  \"weblog\": \"" + ( ! siteWide ? handle : "" ) + "\"," ) ; pw . println ( "  \"tagcounts\": [" ) ; int count = 0 ; for ( Iterator it = tags . iterator ( ) ; it . hasNext ( ) ; ) { TagStat stat = ( TagStat ) it . next ( ) ; pw . print ( "    { \"tag\" : \"" ) ; pw . print ( stat . getName ( ) ) ; pw . print ( "\", " ) ; pw . print ( "\"count\" : " ) ; pw . print ( stat . getCount ( ) ) ; pw . print ( " }" ) ; if ( it . hasNext ( ) ) { pw . println ( ", " ) ; } if ( count ++ > MAX ) { break ; } } pw . println ( "\n  ]\n}" ) ; response . flushBuffer ( ) ; } else if ( "xml" . equals ( format ) ) { URLStrategy urlstrat = roller . getUrlStrategy ( ) ; response . setContentType ( "application/tagdata+xml; charset=utf-8" ) ; PrintWriter pw = response . getWriter ( ) ; pw . println ( "<?xml version=\"1.0\" encoding=\"utf-8\"?>" ) ; pw . println ( "<categories fixed=\"no\" " ) ; pw . println ( "   xmlns=\"http://www.w3.org/2007/app\"" ) ; pw . println ( "   xmlns:atom=\"http://www.w3.org/2005/Atom\"" ) ; pw . println ( "   xmlns:tagdata=\"http://roller.apache.org/ns/tagdata\">" ) ; int count = 0 ; for ( TagStat stat : tags ) { String term = stat . getName ( ) ; String viewURI = urlstrat . getWeblogCollectionURL ( weblog , null , null , null , Collections . singletonList ( stat . getName ( ) ) , 0 , true ) ; int frequency = stat . getCount ( ) ; pw . print ( "<atom:category term=\"" + term + "\" tagdata:frequency=\"" + frequency + "\" " ) ; pw . println ( "tagdata:href=\"" + viewURI + "\" />" ) ; if ( count ++ > MAX ) { break ; } } if ( tags . size ( ) > MAX ) { String nextURI = urlstrat . getWeblogTagsJsonURL ( weblog , true , page + 1 ) ; pw . println ( "<atom:link rel=\"next\" href=\"" + nextURI + "\" />" ) ; } if ( page > 0 ) { String prevURI = urlstrat . getWeblogTagsJsonURL ( weblog , true , page - 1 ) ; pw . println ( "<atom:link rel=\"previous\" href=\"" + prevURI + "\" />" ) ; } pw . println ( "</categories>" ) ; response . flushBuffer ( ) ; } else { response . sendError ( HttpServletResponse . SC_BAD_REQUEST , "Malformed URL" ) ; } } }